import{_ as e,a as t,b as n,c as i}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as d,o as s,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Menambahkan S3 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/upload/s3.md","filePath":"id-ID/upload/s3.md","lastUpdated":1781962217000}'),r={name:"id-ID/upload/s3.md"};function c(u,a,p,k,h,m){return s(),l("div",null,[...a[0]||(a[0]=[o(`<h1 id="menambahkan-s3-channel" tabindex="-1">Menambahkan S3 Channel <a class="header-anchor" href="#menambahkan-s3-channel" aria-label="Permalink to &quot;Menambahkan S3 Channel&quot;">​</a></h1><h2 id="paling-cocok-untuk" tabindex="-1">Paling Cocok Untuk <a class="header-anchor" href="#paling-cocok-untuk" aria-label="Permalink to &quot;Paling Cocok Untuk&quot;">​</a></h2><p>Gunakan S3 channel saat:</p><ul><li>Anda ingin menghubungkan object storage service yang kompatibel dengan S3, seperti Cloudflare R2, Backblaze B2, MinIO, AWS S3, atau provider lain yang compatible.</li><li>Anda lebih nyaman dengan model konfigurasi S3 standar: <code>Endpoint</code>, Access Key, dan Secret Key.</li><li>Anda tidak ingin memakai native Cloudflare R2 binding channel, atau storage provider Anda bukan Cloudflare R2.</li></ul><h2 id="yang-perlu-disiapkan-sebelum-mulai" tabindex="-1">Yang Perlu Disiapkan Sebelum Mulai <a class="header-anchor" href="#yang-perlu-disiapkan-sebelum-mulai" aria-label="Permalink to &quot;Yang Perlu Disiapkan Sebelum Mulai&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>S3 API endpoint dari object storage service.</td></tr><tr><td>Bucket name</td><td>Bucket tempat files disimpan.</td></tr><tr><td>Region</td><td>Storage region. Untuk Cloudflare R2 biasanya <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td></tr><tr><td>CDN domain</td><td>Custom domain opsional untuk file access.</td></tr></tbody></table><p>Contoh Cloudflare R2 lewat S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="di-mana-menambahkannya" tabindex="-1">Di Mana Menambahkannya <a class="header-anchor" href="#di-mana-menambahkannya" aria-label="Permalink to &quot;Di Mana Menambahkannya&quot;">​</a></h2><ol><li>Buka System Settings.</li><li>Masuk ke Upload Settings.</li><li>Klik Add Channel di kanan atas.</li><li>Pilih <code>S3</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama yang mudah dikenali untuk S3 channel, misalnya <code>s3test</code> atau <code>R2-S3</code>.</td><td>Yes</td></tr><tr><td>Enable channel</td><td>Mengontrol apakah channel ini ikut dalam upload selection.</td><td>Recommended</td></tr><tr><td>Endpoint</td><td>Full S3 service endpoint, termasuk <code>https://</code>.</td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>Optional. Jika diisi, generated file links akan memprioritaskan domain ini.</td><td>No</td></tr><tr><td>Bucket name</td><td>Bucket name, misalnya <code>s3test</code> atau <code>img-r2</code>.</td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region. Untuk Cloudflare R2 biasanya <code>auto</code>.</td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td><td>Yes</td></tr><tr><td>Path-style access</td><td>Compatibility switch. Default off. Beberapa MinIO, OpenList, atau self-hosted S3 services mungkin memerlukannya.</td><td>No</td></tr><tr><td>Quota limit</td><td>Mengontrol apakah S3 channel ini ikut upload selection berdasarkan capacity.</td><td>No</td></tr><tr><td>Capacity limit</td><td>Required setelah quota limit aktif, misalnya <code>10 GB</code>.</td><td>Required saat quota limit aktif</td></tr><tr><td>Threshold</td><td>Menghentikan penulisan setelah usage mencapai percentage ini, misalnya <code>90%</code>.</td><td>Required saat quota limit aktif</td></tr><tr><td>Remark</td><td>Catatan untuk maintenance sendiri.</td><td>No</td></tr></tbody></table><h2 id="membuat-cloudflare-r2-s3-api-keys" tabindex="-1">Membuat Cloudflare R2 S3 API Keys <a class="header-anchor" href="#membuat-cloudflare-r2-s3-api-keys" aria-label="Permalink to &quot;Membuat Cloudflare R2 S3 API Keys&quot;">​</a></h2><ol><li>Buka Cloudflare Dashboard.</li><li>Masuk ke <code>R2 Object Storage</code>.</li><li>Cari <code>Manage R2 API Tokens</code> atau entry pengelolaan API token.</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Buat R2 API token yang dapat mengakses target bucket.</li></ol><p><img src="`+e+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li>Copy <code>Access Key ID</code> dan <code>Secret Access Key</code> yang dihasilkan.</li></ol><p><img src="'+t+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>Kembali ke halaman R2 bucket dan pastikan bucket name.</li><li>Catat S3 API endpoint untuk account. Biasanya berbentuk:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><ol><li>Buka Upload Settings.</li><li>Klik Add Channel.</li><li>Pilih <code>S3</code>.</li><li>Masukkan channel name yang mudah dikenali, misalnya <code>s3test</code>.</li><li>Masukkan S3 API endpoint di <code>Endpoint</code>.</li><li>Jika memakai custom CDN, masukkan di <code>Custom CDN domain</code>; jika tidak, biarkan kosong.</li><li>Masukkan bucket name.</li><li>Masukkan region. Untuk contoh Cloudflare R2, gunakan <code>auto</code>.</li><li>Masukkan Access Key ID dan Secret Access Key.</li><li>Biarkan path-style access off kecuali provider secara eksplisit memerlukannya.</li><li>Jika ingin capacity control, aktifkan quota limit lalu masukkan capacity limit dan threshold.</li><li>Klik Save.</li></ol><p><img src="'+n+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="cara-memeriksa" tabindex="-1">Cara Memeriksa <a class="header-anchor" href="#cara-memeriksa" aria-label="Permalink to &quot;Cara Memeriksa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cara Memeriksa</th></tr></thead><tbody><tr><td>Channel card muncul</td><td>Setelah save, halaman Upload Settings harus menampilkan S3 channel card.</td></tr><tr><td>Channel enabled</td><td>Switch di kanan atas card seharusnya tetap on.</td></tr><tr><td>Key fields tersimpan</td><td>Detail view harus menampilkan Endpoint, Bucket, Region, path-style access, dan field terkait.</td></tr><tr><td>Upload berjalan</td><td>Upload test image dan pastikan object muncul di target bucket.</td></tr><tr><td>Link terbuka</td><td>Image link yang dikembalikan setelah upload harus terbuka normal.</td></tr><tr><td>Capacity display berjalan</td><td>Jika quota limit aktif, card harus menunjukkan used capacity dan configured limit.</td></tr></tbody></table><p>S3 capacity statistics dihitung dari local file records ImgBed, bukan dengan query provider bucket secara real time. Setelah S3 configuration disimpan, system akan menghitung ulang quota ledger dari current D1 records.</p><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="perlukah-mengaktifkan-path-style-access" tabindex="-1">Perlukah mengaktifkan path-style access? <a class="header-anchor" href="#perlukah-mengaktifkan-path-style-access" aria-label="Permalink to &quot;Perlukah mengaktifkan path-style access?&quot;">​</a></h3><p>Biasanya tidak.</p><p>Aktifkan hanya jika S3-compatible provider tidak mendukung virtual-hosted-style URLs, atau dokumentasi provider secara eksplisit meminta path-style access. Beberapa MinIO, self-hosted S3, dan OpenList-compatible endpoints mungkin memerlukannya.</p><h3 id="cdn-domain-untuk-apa" tabindex="-1">CDN domain untuk apa? <a class="header-anchor" href="#cdn-domain-untuk-apa" aria-label="Permalink to &quot;CDN domain untuk apa?&quot;">​</a></h3><p>Jika Anda menaruh CDN atau custom access domain di depan bucket, masukkan di sini.</p><p>Setelah dikonfigurasi, generated file links akan memprioritaskan domain ini. Jika tidak memakai CDN, biarkan kosong.</p><h3 id="mengapa-upload-gagal" tabindex="-1">Mengapa upload gagal? <a class="header-anchor" href="#mengapa-upload-gagal" aria-label="Permalink to &quot;Mengapa upload gagal?&quot;">​</a></h3><p>Periksa hal-hal ini terlebih dahulu:</p><ol><li>Endpoint berisi full <code>https://</code> URL.</li><li>Bucket name benar.</li><li>Region sesuai requirement provider.</li><li>Access Key ID dan Secret Access Key disalin lengkap.</li><li>Key punya write permission untuk target bucket.</li><li>Provider tidak memerlukan path-style access, atau path-style access sudah diaktifkan jika diperlukan.</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Siapkan S3 Endpoint, Bucket, Region, Access Key, dan Secret Key</span></span>
<span class="line"><span>-&gt; Buka Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Pilih S3</span></span>
<span class="line"><span>-&gt; Masukkan Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; Masukkan CDN domain jika perlu</span></span>
<span class="line"><span>-&gt; Biarkan path-style access off secara default</span></span>
<span class="line"><span>-&gt; Aktifkan quota limit jika perlu</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Upload test image dan cek hasilnya</span></span></code></pre></div>`,40)])])}const f=d(r,[["render",c]]);export{y as __pageData,f as default};
